#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LENGTH 1000

/*
 * Caesar Cipher Implementation in C
 * university 2022 Scheme - Module 1: Substitution Ciphers
 * 
 * Encryption Formula: C = (P + K) mod 26
 * Decryption Formula: P = (C - K) mod 26
 */

// Encrypts plaintext using Caesar cipher
void caesar_encrypt(char *plaintext, char *ciphertext, int key) {
 int i = 0;

 while (plaintext[i] != '\0') {
 char ch = plaintext[i];

 if (isalpha(ch)) {
 char base = isupper(ch) ? 'A' : 'a';
 // Convert to 0-25, apply shift, wrap with mod 26
 int p = ch - base;
 int c = (p + key) % 26;
 ciphertext[i] = c + base;
 } else {
 // Non-alphabetic characters unchanged
 ciphertext[i] = ch;
 }
 i++;
 }
 ciphertext[i] = '\0';
}

// Decrypts ciphertext using Caesar cipher
void caesar_decrypt(char *ciphertext, char *plaintext, int key) {
 int i = 0;

 while (ciphertext[i] != '\0') {
 char ch = ciphertext[i];

 if (isalpha(ch)) {
 char base = isupper(ch) ? 'A' : 'a';
 // Reverse shift: (C - K) mod 26
 int c = ch - base;
 int p = (c - key) % 26;

 // Handle negative result from modulo
 if (p < 0) {
 p += 26;
 }
 plaintext[i] = p + base;
 } else {
 plaintext[i] = ch;
 }
 i++;
 }
 plaintext[i] = '\0';
}

// Brute-force attack: tries all 25 possible keys
void caesar_brute_force(char *ciphertext) {
 char result[MAX_LENGTH];

 printf("\nBrute-force attack results (25 possible keys):\n");
 printf("--------------------------------------------\n");

 for (int key = 1; key <= 25; key++) {
 caesar_decrypt(ciphertext, result, key);
 printf("Key %2d: %s\n", key, result);
 }
}

// Frequency analysis helper
void frequency_analysis(char *ciphertext) {
 int freq[26] = {0};
 int total = 0;

 // Count letter frequencies
 for (int i = 0; ciphertext[i] != '\0'; i++) {
 if (isalpha(ciphertext[i])) {
 int index = toupper(ciphertext[i]) - 'A';
 freq[index]++;
 total++;
 }
 }

 // Find most frequent letter
 int max_freq = 0;
 int max_letter = 0;
 printf("\nLetter frequencies in ciphertext:\n");
 printf("Letter Count Percentage\n");
 printf("---------------------------\n");

 for (int i = 0; i < 26; i++) {
 if (freq[i] > 0) {
 double percentage = (freq[i] * 100.0) / total;
 printf(" %c %3d %.2f%%\n", 'A' + i, freq[i], percentage);

 if (freq[i] > max_freq) {
 max_freq = freq[i];
 max_letter = i;
 }
 }
 }

 // Estimate key using frequency analysis
 // Assuming 'E' (index 4) is most common in English
 int e_index = 4; // 'E' is at index 4
 int estimated_key = (max_letter - e_index + 26) % 26;

 printf("\nFrequency Analysis Conclusion:\n");
 printf("Most frequent letter: %c\n", 'A' + max_letter);
 printf("Assuming it encrypts 'E', estimated key: %d\n", estimated_key);
}

