import java.util.*;

/**
 * Caesar Cipher Implementation in Java
 * university 2022 Scheme - Module 1: Substitution Ciphers
 * 
 * Encryption Formula: C = (P + K) mod 26
 * Decryption Formula: P = (C - K) mod 26
 */
public class CaesarCipher {

 /**
 * Encrypts plaintext using Caesar cipher
 * @param plaintext The message to encrypt
 * @param key The shift value (1-25)
 * @return Encrypted ciphertext
 */
 public static String encrypt(String plaintext, int key) {
 StringBuilder ciphertext = new StringBuilder();

 for (char ch : plaintext.toCharArray()) {
 if (Character.isLetter(ch)) {
 char base = Character.isUpperCase(ch) ? 'A' : 'a';
 int p = ch - base;
 int c = (p + key) % 26;
 ciphertext.append((char) (c + base));
 } else {
 ciphertext.append(ch);
 }
 }

 return ciphertext.toString();
 }

 /**
 * Decrypts ciphertext using Caesar cipher
 * @param ciphertext The encrypted message
 * @param key The shift value used during encryption
 * @return Decrypted plaintext
 */
 public static String decrypt(String ciphertext, int key) {
 // Decryption is encryption with negative key
 StringBuilder plaintext = new StringBuilder();

 for (char ch : ciphertext.toCharArray()) {
 if (Character.isLetter(ch)) {
 char base = Character.isUpperCase(ch) ? 'A' : 'a';
 int c = ch - base;
 int p = (c - key) % 26;

 // Handle negative modulo
 if (p < 0) {
 p += 26;
 }
 plaintext.append((char) (p + base));
 } else {
 plaintext.append(ch);
 }
 }

 return plaintext.toString();
 }

 /**
 * Breaks Caesar cipher using brute-force attack
 * @param ciphertext The encrypted message to break
 * @return Map of possible plaintexts with their keys
 */
 public static Map<Integer, String> bruteForce(String ciphertext) {
 Map<Integer, String> results = new HashMap<>();

 for (int key = 1; key <= 25; key++) {
 results.put(key, decrypt(ciphertext, key));
 }

 return results;
 }

 /**
 * Performs frequency analysis on ciphertext
 * @param ciphertext The encrypted message
 * @return Map of letter frequencies (as percentages)
 */
 public static Map<Character, Double> frequencyAnalysis(String ciphertext) {
 Map<Character, Integer> counts = new HashMap<>();
 int total = 0;

 for (char ch : ciphertext.toCharArray()) {
 if (Character.isLetter(ch)) {
 char upper = Character.toUpperCase(ch);
 counts.put(upper, counts.getOrDefault(upper, 0) + 1);
 total++;
 }
 }

 // Convert to percentages
 Map<Character, Double> frequencies = new HashMap<>();
 for (Map.Entry<Character, Integer> entry : counts.entrySet()) {
 frequencies.put(entry.getKey(), (entry.getValue() * 100.0) / total);
 }

 return frequencies;
 }

 /**
 * Estimates the key using frequency analysis
 * Assumes most frequent letter in ciphertext = 'E' + key
 * @param ciphertext The encrypted message
 * @return Estimated key
 */
 public static int estimateKey(String ciphertext) {
 Map<Character, Double> freq = frequencyAnalysis(ciphertext);

 // Find most frequent letter
 char mostFrequent = 'A';
 double maxFreq = 0;

 for (Map.Entry<Character, Double> entry : freq.entrySet()) {
 if (entry.getValue() > maxFreq) {
 maxFreq = entry.getValue();
 mostFrequent = entry.getKey();
 }
 }

 // 'E' is most common in English (index 4)
 int eIndex = 4;
 int mostFreqIndex = mostFrequent - 'A';

 return (mostFreqIndex - eIndex + 26) % 26;
 }

 public static void main(String[] args) {
 System.out.println("========================================");
 System.out.println(" CAESAR CIPHER - JAVA IMPLEMENTATION");
 System.out.println("========================================");

 // Example 1: Basic encryption from textbook
 String plaintext = "SECRET";
 int key = 3;

 String ciphertext = encrypt(plaintext, key);
 System.out.println("\n--- Example 1: Textbook Example ---");
 System.out.println("Plaintext: " + plaintext);
 System.out.println("Key: " + key);
 System.out.println("Ciphertext: " + ciphertext);
 System.out.println("Decrypted: " + decrypt(ciphertext, key));

 // Example 2: Brute force attack
 String message = "ATTACK AT DAWN";
 int shift = 7;
 ciphertext = encrypt(message, shift);

 System.out.println("\n--- Example 2: Brute Force Attack ---");
 System.out.println("Original: " + message);
 System.out.println("Encrypted: " + ciphertext);
 System.out.println("\nTrying all possible keys:");

 Map<Integer, String> results = bruteForce(ciphertext);
 for (Map.Entry<Integer, String> entry : results.entrySet()) {
 System.out.println("Key " + String.format("%2d", entry.getKey()) + ": " + entry.getValue());
 }

 // Example 3: Frequency Analysis
 System.out.println("\n--- Example 3: Frequency Analysis ---");
 String longText = "THE QUICK BROWN FOX JUMPS OVER THE LAZY DOG";
 int k = 5;
 ciphertext = encrypt(longText, k);

 System.out.println("Original: " + longText);
 System.out.println("Encrypted: " + ciphertext);

 Map<Character, Double> freq = frequencyAnalysis(ciphertext);

 // Sort by frequency
 List<Map.Entry<Character, Double>> sorted = 
 new ArrayList<>(freq.entrySet());
 sorted.sort(Map.Entry.<Character, Double>comparingByValue().reversed());

 System.out.println("\nTop 5 most frequent letters:");
 for (int i = 0; i < Math.min(5, sorted.size()); i++) {
 Map.Entry<Character, Double> entry = sorted.get(i);
 System.out.println(" " + entry.getKey() + ": " + String.format("%.2f", entry.getValue()) + "%");
 }

 int estimatedKey = estimateKey(ciphertext);
 System.out.println("\nEstimated key (using frequency analysis): " + estimatedKey);
 System.out.println("Actual key: " + k);

 System.out.println("\n========================================");
 System.out.println("Security Analysis:");
 System.out.println("- Key space: 25 possible keys");
 System.out.println("- Brute force: Trivially breaks in milliseconds");
 System.out.println("- Frequency analysis: Also effective");
 System.out.println("========================================");
 }
}
